#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <chrono>
#include <cuda_runtime.h>

template<typename T>
void verify(const T* ref_out, const T* out, int64_t n)
{
  int error = memcmp(ref_out, out, n * sizeof(T));
  if (error) {
    for (int64_t i = 0; i < n; i++) {
      if (ref_out[i] != out[i]) {
        printf("@%zu: %lf != %lf\n", i, (double)ref_out[i], (double)out[i]);
        break;
      }
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}


#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
__global__ void scanKernel(T* in, T* out, int64_t num_blocks)
{
  int64_t bid = blockIdx.x;
  if (bid >= num_blocks) return;

  T temp[N];
  T *t_in  = in + bid * N;
  T *t_out = out + bid * N;

  int thid = threadIdx.x;
  int offset = 1;

  temp[2*thid]   = t_in[2*thid];
  temp[2*thid+1] = t_in[2*thid+1];

  for (int d = N >> 1; d > 0; d >>= 1)
  {
    __syncthreads();
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  if (thid == 0) temp[N-1] = 0; 
  for (int d = 1; d < N; d *= 2) 
  {
    offset >>= 1;
    __syncthreads();
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
  }
  t_out[2*thid] = temp[2*thid];
  t_out[2*thid+1] = temp[2*thid+1];
}

template<typename T, int N>
__global__ void scanKernelNoBankConflict(T* in, T* out, int64_t num_blocks)
{
  int64_t bid = blockIdx.x;
  if (bid >= num_blocks) return;

  T temp[2*N];
  T *t_in  = in + bid * N;
  T *t_out = out + bid * N;

  int thid = threadIdx.x;
  int a = thid;
  int b = a + (N/2);
  int oa = OFFSET(a);
  int ob = OFFSET(b);

  temp[a + oa] = t_in[a];
  temp[b + ob] = t_in[b];

  int offset = 1;
  for (int d = N >> 1; d > 0; d >>= 1)
  {
    __syncthreads();
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      ai += OFFSET(ai);
      bi += OFFSET(bi);
      temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  if (thid == 0) temp[N-1+OFFSET(N-1)] = 0; 
  for (int d = 1; d < N; d *= 2) 
  {
    offset >>= 1;
    __syncthreads();
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      ai += OFFSET(ai);
      bi += OFFSET(bi);
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
  }
  __syncthreads();

  t_out[a] = temp[a + oa];
  t_out[b] = temp[b + ob];
}

template<typename T, int N>
void runTest(const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;
  int64_t nelems = num_blocks * N; 
  int64_t bytes = nelems * sizeof(T);

  T *h_in = (T*) malloc(bytes);
  T *h_out = (T*) malloc(bytes);
  T *h_ref_out = (T*) malloc(bytes);

  T *d_in, *d_out;
  cudaMalloc(&d_in, bytes);
  cudaMalloc(&d_out, bytes);

  srand(123);
  for (int64_t i = 0; i < nelems; i++) h_in[i] = rand() % 5 + 1;

  T *t_in = h_in;
  T *t_out = h_ref_out;
  for (int64_t i = 0; i < num_blocks; i++) {
    t_out[0] = 0;
    for (int j = 1; j < N; j++)
      t_out[j] = t_out[j-1] + t_in[j-1];
    t_out += N;
    t_in += N;
  }

  cudaMemcpy(d_in, h_in, bytes, cudaMemcpyHostToDevice);

  cudaEvent_t start, end;
  cudaEventCreate(&start);
  cudaEventCreate(&end);

  cudaEventRecord(start);

  for (int i = 0; i < repeat; i++) {
    scanKernel<T, N><<num_blocks, N/2>>>(d_in, d_out, num_blocks);
  }

  cudaEventRecord(end);
  cudaEventSynchronize(end);

  float time_ms = 0;
  cudaEventElapsedTime(&time_ms, start, end);
  auto time = (double)(time_ms * 1000);

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time * 1e-3f) / repeat);
  }

  cudaMemcpy(h_out, d_out, bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(h_ref_out, h_out, nelems);

  cudaEventRecord(start);
  for (int i = 0; i < repeat; i++) {
    scanKernelNoBankConflict<T, N><<num_blocks, N/2>>>(d_in, d_out, num_blocks);
  }
  cudaEventRecord(end);
  cudaEventSynchronize(end);

  float bcao_time_ms = 0;
  cudaEventElapsedTime(&bcao_time_ms, start, end);
  auto bcao_time = (double)(bcao_time_ms * 1000);

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time - bcao_time) * 1.0 / time * 100);
  }

  cudaMemcpy(h_out, d_out, bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(h_ref_out, h_out, nelems);

  cudaFree(d_in);
  cudaFree(d_out);
  cudaEventDestroy(start);
  cudaEventDestroy(end);
  free(h_in);
  free(h_out);
  free(h_ref_out);
}

template<int N>
void run(const int n, const int repeat) {
  for (int i = 0; i < 2; i++) {
    bool report_timing = i > 0;
    printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest<char, N>(n, repeat, report_timing);
    runTest<short, N>(n, repeat, report_timing);
    runTest<int, N>(n, repeat, report_timing);
    runTest<long, N>(n, repeat, report_timing);
  }
}

int main(int argc, char* argv[])
{
  if (argc != 3) {
    printf("Usage: %s <number of elements> <repeat>\n", argv[0]);
    return 1;
  }
  const int n = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  run<128>(n, repeat);
  run<256>(n, repeat);
  run<512>(n, repeat);
  run<1024>(n, repeat);
  run<2048>(n, repeat);

  return 0;
}
